## Comptime Functions

```aria
comptime fn is_power_of_2(n: i32) -> bool {
    return n > 0 && (n & (n - 1)) == 0;
}

comptime {
    if !is_power_of_2(BUFFER_SIZE) {
        @compile_error("BUFFER_SIZE must be power of 2");
