func:lcm_i32 = int32(int32:a, int32:b) {
int32:zero = 0i32;

    if (a == zero || b == zero) {
        return zero;
    } else {}

    int32:abs_a = a;
    int32:abs_b = b;

    if (abs_a < zero) {
        abs_a = zero - abs_a;
    } else {}

