func:partition_i64 = int32(int64->:arr, int32:low, int32:high) {
int64:pivot = arr[high];
    int32:i = low - 1;

    int32:j = low;
    till(high, 1i64) {
        if (arr[j] < pivot) {
            i = i + 1;
            int64:temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
        j = j + 1;
    }

    int64:temp = arr[i + 1];
    arr[i + 1] = arr[high];
    arr[high] = temp;

    return i + 1;
};
}
