/// Count number of set bits (population count)
func:popcount_i32 = int32(int32:n) {
    int32:count = 0i32;
    int32:val = n;

    // Handle negative numbers
    bool:negative = (val < 0);
    if (negative) {
        val = (0 - val);
    } else {}

    while (val != 0) {
        int32:bit = (val - ((val / 2) * 2));  // Manual modulo 2
        bool:is_one = (bit == 1);
        if (is_one) {
            count = (count + 1);
        } else {}
        val = (val / 2);
    }

    pass(count);
};

/// Check if specific bit is set
func:bit_test = bool(int32:n, int32:pos) {
    int32:val = n;
    int32:i = 0i32;

    // Shift right by pos positions
    while (i < pos) {
        val = (val / 2);
        i = (i + 1);
    }

    int32:bit = (val - ((val / 2) * 2));  // Check lowest bit
    bool:result = false;
    bool:is_set = (bit == 1);
    if (is_set) {
        result = true;
    } else {
        result = false;
    }
    pass(result);
};

/// Set specific bit
func:bit_set = uint32(uint32:n, uint32:pos) {
    uint32:mask = 1i32;
    uint32:i = 0i32;
    uint32:two = 2i32;
    uint32:one = 1i32;

    // Calculate 2^pos
    while (i < pos) {
        mask = (mask * two);
        i = (i + one);
    }

    uint32:result = (n | mask);  // Bitwise OR
    pass(result);
};

/// Clear specific bit
func:bit_clear = uint32(uint32:n, uint32:pos) {
    uint32:mask = 1i32;
    uint32:i = 0i32;
    uint32:two = 2i32;
    uint32:one = 1i32;

    // Calculate 2^pos
    while (i < pos) {
        mask = (mask * two);
        i = (i + one);
    }

    uint32:inv_mask = (~mask);  // Bitwise NOT
    uint32:result = (n & inv_mask);  // Bitwise AND
    pass(result);
};

/// Flip specific bit
func:bit_flip = uint32(uint32:n, uint32:pos) {
    uint32:mask = 1i32;
    uint32:i = 0i32;
    uint32:two = 2i32;
    uint32:one = 1i32;

    // Calculate 2^pos
    while (i < pos) {
        mask = (mask * two);
        i = (i + one);
    }

    uint32:result = (n ^ mask);  // Bitwise XOR
    pass(result);
};

/// Rotate left
func:rotate_left_u32 = uint32(uint32:n, uint32:shift) {
    uint32:bits = 32;
    uint32:normalized = (shift - ((shift / bits) * bits));  // shift % 32

    uint32:left_part = (n << normalized);
    uint32:right_shift_amt = (bits - normalized);
    uint32:right_part = (n >> right_shift_amt);

    uint32:result = (left_part | right_part);
    pass(result);
};

/// Rotate right
func:rotate_right_u32 = uint32(uint32:n, uint32:shift) {
    uint32:bits = 32;
    uint32:normalized = (shift - ((shift / bits) * bits));  // shift % 32

    uint32:right_part = (n >> normalized);
    uint32:left_shift_amt = (bits - normalized);
    uint32:left_part = (n << left_shift_amt);

    uint32:result = (left_part | right_part);
    pass(result);
};

/// Check if power of 2
func:is_power_of_two = bool(uint32:n) {
    bool:result = false;
    uint32:zero = 0i32;
    bool:positive = (n > zero);

    if (positive) {
        uint32:one = 1i32;
        uint32:n_minus_1 = (n - one);
        uint32:test = (n & n_minus_1);
        bool:is_zero = (test == zero);
        if (is_zero) {
            result = true;
        } else {
            result = false;
        }
    } else {
        result = false;
    }

    pass(result);
};

