## Common Patterns

### Thread-Safe Counter

```aria
import std.sync.Atomic;

struct Counter {
    value: Atomic<i32>,
}

impl Counter {
    pub fn new() -> Counter {
        return Counter {
            value: Atomic.new(0),
        };
    }

    pub fn increment() {
        self.value.fetch_add(1);
    }

    pub fn get() -> i32 {
        return self.value.load();
    }
}

// Use from multiple threads
counter: Counter = Counter.new();

fn worker() {
    till(999, 1) {
        counter.increment();  // Thread-safe!
    }
}
```

