### Spin Lock

```aria
import std.sync.Atomic;

struct SpinLock {
    locked: Atomic<bool>,
}

impl SpinLock {
    pub fn new() -> SpinLock {
        return SpinLock {
            locked: Atomic.new(false),
        };
    }

    pub fn lock() {
        while !self.locked.compare_and_swap(false, true) {
            // Spin until we acquire the lock
            yield_cpu();
        }
    }

    pub fn unlock() {
        self.locked.store(false);
    }
}
```

